// generated by gpt hehe

function setActiveSidebar() {
  const currentPath = window.location.pathname;

  document.querySelectorAll(".sidebar-link").forEach((link) => {
    const url = new URL(link.getAttribute("hx-get"), window.location.origin);

    link.classList.toggle("active", url.pathname === currentPath);
  });
}

document.addEventListener("DOMContentLoaded", setActiveSidebar);

document.body.addEventListener("htmx:afterSettle", setActiveSidebar);
